mapper.update:
UPDATE comment
SET content = #{content},
    comment_type = #{commentType}
WHERE comment_id = #{commentId}

mapper.select:
SELECT DISTINCT u.user_id AS userId, u.name AS name, u.user_name AS userName, u.avatar_url AS avatarUrl, reviewers.comment_type AS commentType FROM ( -- comment 작성한 유저 SELECT user_id, comment_type, pr_id, repo_id FROM comment WHERE pr_id = #{prId} AND repo_id = #{repoId}
UNION ALL
-- reply 작성한 유저 SELECT user_id, recomment_type AS comment_type, pr_id, repo_id FROM reply WHERE pr_id = #{prId} AND repo_id = #{repoId} ) AS reviewers JOIN users u ON reviewers.user_id = u.user_id ORDER BY userId;

